#!/usr/bin/env -S npx ts-node -r tsconfig-paths/register
/**
 * Example: Query a foundation model with SSE streaming
 *
 * This example demonstrates:
 * - Querying a foundation model endpoint with streaming enabled
 * - Parsing Server-Sent Events (SSE) responses using eventsource-parser
 * - Displaying streamed content as it arrives
 * - Handling stream completion and errors
 *
 * Prerequisites:
 * - DATABRICKS_HOST environment variable
 * - Valid authentication (PAT, OAuth M2M, or other)
 * - Access to foundation model endpoints
 * - MODEL_NAME environment variable (optional, defaults to "databricks-meta-llama-3-1-8b-instruct")
 *
 * Usage:
 *   npx ts-node examples/workspace/ml/query-model-streaming.ts
 *   MODEL_NAME="my-custom-model" npx ts-node examples/workspace/ml/query-model-streaming.ts
 */

import {WorkspaceClient} from "@databricks/sdk-experimental";
import type {serving} from "@databricks/sdk-experimental";
import {
    EventSourceParserStream,
    type EventSourceMessage,
} from "eventsource-parser/stream";

/**
 * Token usage information returned by the API
 */
interface TokenUsage {
    prompt_tokens?: number;
    completion_tokens?: number;
    total_tokens?: number;
}

/**
 * Parsed and typed SSE message
 */
type SSEMessage =
    | {
          type: "chunk";
          data: {
              id: string;
              object: string;
              created: number;
              model: string;
              choices: Array<{
                  index: number;
                  delta: {
                      role?: string;
                      content?: string;
                  };
                  finish_reason: string | null;
                  logprobs: unknown | null;
              }>;
              usage?: TokenUsage;
          };
      }
    | {type: "done"}
    | {type: "error"; error: string};

/**
 * Query a serving endpoint with streaming enabled.
 * Returns an async iterator that yields parsed and typed SSE messages.
 *
 * This function makes a direct API request with streaming enabled and uses
 * the eventsource-parser library to parse Server-Sent Events.
 *
 * @param client - The WorkspaceClient instance
 * @param endpointName - The name of the serving endpoint
 * @param payload - The request payload (messages, max_tokens, etc.)
 * @returns AsyncIterableIterator of SSEMessage objects (chunk, done, or error)
 *
 * @example
 * ```typescript
 * const stream = queryStreaming(client, "llama-3-3-70b", {
 *     messages: [
 *         { role: "system", content: "You are a helpful assistant." },
 *         { role: "user", content: "What is Apache Spark?" }
 *     ],
 *     max_tokens: 500,
 *     temperature: 0.7,
 * });
 *
 * for await (const message of stream) {
 *     switch (message.type) {
 *         case "chunk":
 *             console.log(message.data);
 *             break;
 *         case "done":
 *             console.log("Stream completed");
 *             break;
 *         case "error":
 *             console.error("Stream error:", message.error);
 *             break;
 *     }
 * }
 * ```
 */
async function* queryStreaming(
    client: WorkspaceClient,
    payload: Omit<serving.QueryEndpointInput, "stream">
): AsyncIterableIterator<SSEMessage> {
    const response = (await client.apiClient.request({
        path: `/serving-endpoints/${payload.name}/invocations`,
        method: "POST",
        headers: new Headers({
            "Content-Type": "application/json",
            "Accept": "text/event-stream",
        }),
        payload: {
            ...payload,
            name: undefined,
            stream: true,
        },
        raw: true, // Get the raw stream instead of parsed JSON
    })) as {contents: ReadableStream<Uint8Array>};

    if (!response.contents) {
        throw new Error("No response body received");
    }

    const stream = response.contents
        .pipeThrough(new TextDecoderStream() as any)
        .pipeThrough(new EventSourceParserStream());

    const reader = stream.getReader();
    try {
        while (true) {
            const {done, value} = await reader.read();
            if (done) {
                break;
            }

            const event = value as EventSourceMessage;
            if (event.data === "[DONE]") {
                yield {type: "done"};
                continue;
            }

            try {
                const parsed = JSON.parse(event.data);
                yield {
                    type: "chunk",
                    data: parsed,
                } as Extract<SSEMessage, {type: "chunk"}>;
            } catch (error) {
                yield {
                    type: "error",
                    error: `Failed to parse SSE data: ${error}`,
                };
            }
        }
    } finally {
        reader.releaseLock();
    }
}

async function main() {
    const client = new WorkspaceClient({});

    // Foundation model endpoint name (read from environment variable with fallback)
    const endpointName =
        process.env.MODEL_NAME || "databricks-meta-llama-3-1-8b-instruct";

    console.log(`Querying foundation model with streaming: ${endpointName}`);

    const stream = queryStreaming(client, {
        name: endpointName,
        messages: [
            {
                role: "system",
                content:
                    "You are a helpful AI assistant that provides concise and accurate answers about data engineering and analytics.",
            },
            {
                role: "user",
                content:
                    "Explain what Apache Spark is and why it's important for big data processing. Keep it concise.",
            },
        ],
        max_tokens: 500,
        temperature: 0.7,
    });

    console.log("\nStreaming response:\n");
    let lastUsage: TokenUsage | null = null;

    for await (const message of stream) {
        switch (message.type) {
            case "chunk": {
                // Track usage information from each chunk
                if (message.data.usage) {
                    lastUsage = message.data.usage;
                }

                // Display streaming content
                for (const choice of message.data.choices) {
                    if (choice.delta.content) {
                        process.stdout.write(choice.delta.content);
                    }
                }
                break;
            }

            case "done": {
                console.log("\n\n✓ Stream completed");
                break;
            }

            case "error": {
                console.error(`\n✗ Stream error: ${message.error}`);
                break;
            }
        }
    }

    // Display token usage if available (from last chunk)
    if (lastUsage) {
        console.log(`\nToken Usage:`);
        console.log(`  Prompt tokens: ${lastUsage.prompt_tokens || 0}`);
        console.log(`  Completion tokens: ${lastUsage.completion_tokens || 0}`);
        console.log(`  Total tokens: ${lastUsage.total_tokens || 0}`);
    }
}

main().catch((error) => {
    console.error("Failed to run example:", error);
    process.exit(1);
});
